import { useRef, useEffect } from "react";
import "./MovieRow.css";

function MovieRow({ title, movies }) {
  const rowRef = useRef();

  if (!movies || movies.length === 0) return null;

  const scroll = (direction) => {
    const { current } = rowRef;
    const scrollAmount = current.offsetWidth;

    if (direction === "next") {
      current.scrollLeft += scrollAmount;
    } else {
      current.scrollLeft -= scrollAmount;
    }
  };

  // ✅ auto slide mỗi 5s
  useEffect(() => {
    const interval = setInterval(() => {
      const { current } = rowRef;

      if (!current) return;

      const maxScroll = current.scrollWidth - current.clientWidth;

      // nếu tới cuối thì quay lại đầu
      if (current.scrollLeft >= maxScroll) {
        current.scrollLeft = 0;
      } else {
        current.scrollLeft += current.offsetWidth;
      }
    }, 5000); // ⏱️ 5 giây

    return () => clearInterval(interval);
  }, []);

  return (
    <div className="movie-row">
      <h2>{title}</h2>

      {/* nút */}
      <button className="nav prev" onClick={() => scroll("prev")}>❮</button>
      <button className="nav next" onClick={() => scroll("next")}>❯</button>

      <div className="row" ref={rowRef}>
        {movies.slice(0, 10).map((movie) => (
          <div key={movie.id} className="card">
            <img src={movie.image || ""} alt={movie.title} />
          </div>
        ))}
      </div>
    </div>
  );
}

export default MovieRow;
